import { type ClockworkVerdict } from './universe/verdict';
import { type ChaosConfig, type UniverseBenchmarkMetrics } from './void-game-types';

/**
 * Results from a manifold execution.
 */
export interface ManifoldResult {
  readonly durationMs: number;
  readonly metrics: UniverseBenchmarkMetrics;
  readonly activeSurvivors: number;
  readonly survivalRate: number;
  readonly clinamenPressure: number;
  readonly verdict?: ClockworkVerdict;
}

/**
 * A ManifoldExecutor is a high-performance substrate for executing
 * Gnosis topologies against massive agent swarms.
 */
export interface ManifoldExecutor {
  /**
   * Execute a parallel swarm simulation.
   * 
   * @param seed The universe seed for determinism.
   * @param rounds Number of rounds to simulate.
   * @param config The thermodynamic chaos configuration.
   */
  execute(
    seed: bigint,
    rounds: number,
    config: ChaosConfig
  ): Promise<ManifoldResult>;
}
